int parse_input(char* input, char* buffer, size_t max_size) {
    if (!input || !buffer || max_size == 0) return -1;

    // Check input length before copying
    size_t input_len = strlen(input);
    if (input_len >= max_size) {
        return -1;  // Input too long
    }

    // Safe string copy
    strncpy(buffer, input, max_size - 1);
    buffer[max_size - 1] = '\0';

    return (int)strlen(buffer);
}

